  ('real-estate-moex-02779', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲受乙委任代售房屋一棟，卻將所售屋款挪為己用。問下列敘述何者正確？', '["甲應支付利息，但如乙受有損害，甲不須賠償", "甲無須支付利息，但如乙受有損害，甲須賠償", "甲僅於乙受有損害時，甲須賠償並支付利息", "甲應支付利息，且如乙受有損害，甲須賠償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
